class TOCWrapper{constructor(){this.headings=[]}isHeadingWrappedInDiv(heading){if(!heading.parentElement)return false;const parent=heading.parentElement;if(parent.tagName.toLowerCase()!=="div")return false;if(parent.classList.contains("content__entry"))return false;return true}collectHeadings(){this.headings=[];const contentEntry=document.querySelector(".content__entry");if(!contentEntry)return this.headings;const allHeadings=contentEntry.querySelectorAll("h2, h3, h4, h5, h6");let foundFirstH2=false;for(let heading of allHeadings){if(this.isHeadingWrappedInDiv(heading)){continue}if(heading.tagName.toLowerCase()==="h2"){foundFirstH2=true;this.headings.push(heading)}else if(foundFirstH2){this.headings.push(heading)}}return this.headings}ensureHeadingIds(){this.headings.forEach((heading,index)=>{if(!heading.id){heading.id=`heading-${index}`}})}getHeadingLevel(heading){return parseInt(heading.tagName.toLowerCase().substring(1),10)}createTocList(){const ul=document.createElement("ul");if(this.headings.length===0){return ul}let currentLevel=this.getHeadingLevel(this.headings[0]);let currentList=ul;const listStack=[{level:currentLevel,list:ul}];this.headings.forEach(heading=>{const headingLevel=this.getHeadingLevel(heading);const targetLevel=Math.min(headingLevel,currentLevel+1);while(targetLevel>currentLevel){const newList=document.createElement("ul");if(currentList.lastElementChild){currentList.lastElementChild.appendChild(newList)}else{currentList.appendChild(document.createElement("li")).appendChild(newList)}currentList=newList;currentLevel++;listStack.push({level:currentLevel,list:newList})}while(headingLevel<currentLevel&&listStack.length>1){listStack.pop();currentList=listStack[listStack.length-1].list;currentLevel=listStack[listStack.length-1].level}const li=document.createElement("li");const a=document.createElement("a");a.href=`#${heading.id}`;a.textContent=heading.textContent;li.appendChild(a);currentList.appendChild(li)});return ul}createTocStructure(){const wrapper=document.createElement("aside");wrapper.className="toc-wrapper";wrapper.setAttribute("aria-label","Table of Contents");const header=document.createElement("div");header.className="toc-header";const title=document.createElement("h3");title.className="toc-title";title.textContent="Contents";header.appendChild(title);const toggleBtn=document.createElement("button");toggleBtn.type="button";toggleBtn.className="toc-toggle";toggleBtn.setAttribute("aria-label","Toggle table of contents");toggleBtn.setAttribute("aria-expanded","true");toggleBtn.innerHTML='<span class="toc-toggle-icon">✕</span>';header.appendChild(toggleBtn);wrapper.appendChild(header);const nav=document.createElement("nav");nav.className="toc-nav";const tocList=this.createTocList();nav.appendChild(tocList);wrapper.appendChild(nav);return wrapper}insertToc(){const contentEntry=document.querySelector(".content__entry");if(!contentEntry)return null;const tocStructure=this.createTocStructure();const contentInner=contentEntry.closest(".content__inner");if(contentInner){const content=contentInner.closest(".content");if(content){content.insertBefore(tocStructure,contentInner);return tocStructure}}const wrapperParent=contentEntry.parentElement;if(wrapperParent&&wrapperParent.classList.contains("content__inner")){wrapperParent.insertBefore(tocStructure,contentEntry);return tocStructure}contentEntry.insertBefore(tocStructure,contentEntry.firstChild);return tocStructure}init(){this.collectHeadings();if(this.headings.length===0){return null}this.ensureHeadingIds();const toc=this.insertToc();return toc}}